<?php
namespace App\Http\Controllers\Auth;
use App\Http\Controllers\Controller;use App\Models\SecurityEventLog;use App\Services\Audit\AuditLogger;use Illuminate\Http\Request;use Illuminate\Support\Facades\Auth;
class LoginController extends Controller { public function create(){ return view('pages.auth.login'); } public function store(Request $request, AuditLogger $auditLogger){ $credentials=$request->validate(['email'=>['required','email'],'password'=>['required','string']]); if(!Auth::attempt($credentials)){ SecurityEventLog::query()->create(['event_type'=>'failed_login','severity'=>'medium','event_detail'=>'Internal login failed','ip_address'=>$request->ip(),'event_time'=>now()]); return back()->withErrors(['email'=>'Kredensial tidak valid.']); } $request->session()->regenerate(); $request->user()->update(['last_login_at'=>now()]); $auditLogger->log('login_success',$request,'users',$request->user()->id); return redirect()->intended('/dashboard/interaktif'); } public function destroy(Request $request, AuditLogger $auditLogger){ $auditLogger->log('logout',$request,'users',$request->user()?->id); Auth::logout(); $request->session()->invalidate(); $request->session()->regenerateToken(); return redirect('/login'); }}
